import{_ as a,o,c as r,ae as i}from"./chunks/framework.DZmDXV-X.js";const m=JSON.parse('{"title":"Plano de Ajuste do Deploy (VitePress CI/CD)","description":"","frontmatter":{},"headers":[],"relativePath":"PLAN.md","filePath":"PLAN.md"}'),t={name:"PLAN.md"};function s(d,e,n,l,c,u){return o(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="plano-de-ajuste-do-deploy-vitepress-ci-cd" tabindex="-1">Plano de Ajuste do Deploy (VitePress CI/CD) <a class="header-anchor" href="#plano-de-ajuste-do-deploy-vitepress-ci-cd" aria-label="Permalink to &quot;Plano de Ajuste do Deploy (VitePress CI/CD)&quot;">​</a></h1><h2 id="objetivo" tabindex="-1">Objetivo <a class="header-anchor" href="#objetivo" aria-label="Permalink to &quot;Objetivo&quot;">​</a></h2><p>Resolver os erros de dependência e compilação do fluxo contínuo do Github Actions. Isso será feito homologando a estrutura de pacotes NodeJS recém-criada localmente pelo <code>ag-kit</code> (<code>package.json</code>, <code>package-lock.json</code>) no ambiente de produção.</p><h2 id="agentes-envolvidos" tabindex="-1">Agentes Envolvidos <a class="header-anchor" href="#agentes-envolvidos" aria-label="Permalink to &quot;Agentes Envolvidos&quot;">​</a></h2><ul><li><strong>project-planner</strong>: Orquestração e planejamento.</li><li><strong>devops-engineer</strong>: Controle de versão e CI/CD.</li><li><strong>security-auditor</strong>: Verificações de segurança antes do push.</li></ul><hr><h2 id="passo-a-passo-implementacao" tabindex="-1">Passo a Passo (Implementação) <a class="header-anchor" href="#passo-a-passo-implementacao" aria-label="Permalink to &quot;Passo a Passo (Implementação)&quot;">​</a></h2><h3 id="_1-auditoria-de-seguranca-security-auditor" tabindex="-1">1. Auditoria de Segurança (<code>security-auditor</code>) <a class="header-anchor" href="#_1-auditoria-de-seguranca-security-auditor" aria-label="Permalink to &quot;1. Auditoria de Segurança (`security-auditor`)&quot;">​</a></h3><ul><li>Verificar detalhadamente os metadados gerados dentro da pasta local <code>.agent/</code> pelo <em>Antigravity Kit</em>.</li><li>Garantir que nenhum arquivo temporário, sensível ou binário pesado seja indevidamente adicionado ao repositório.</li><li>Revisar a integridade protetiva do <code>.gitignore</code>.</li></ul><h3 id="_2-infraestrutura-e-controle-de-versao-devops-engineer" tabindex="-1">2. Infraestrutura e Controle de Versão (<code>devops-engineer</code>) <a class="header-anchor" href="#_2-infraestrutura-e-controle-de-versao-devops-engineer" aria-label="Permalink to &quot;2. Infraestrutura e Controle de Versão (`devops-engineer`)&quot;">​</a></h3><ul><li>Incluir os pacotes mestres de rastreio (<code>package.json</code>, <code>package-lock.json</code>) no histórico Git.</li><li>Incluir a documentação das novas ferramentas da pasta <code>.agent</code>.</li><li>Criar a rotina de commit semântico oficial explicitando a correção da infraestrutura.</li><li>Efetuar o <code>git push origin main</code> com segurança total para reinicializar o motor do <strong>GitHub Actions</strong>.</li></ul><h3 id="_3-scripts-de-verificacao" tabindex="-1">3. Scripts de Verificação <a class="header-anchor" href="#_3-scripts-de-verificacao" aria-label="Permalink to &quot;3. Scripts de Verificação&quot;">​</a></h3><ul><li>Rodar o módulo de segurança/lint configurado via <code>ag-kit</code> (ex: <code>security_scan.py</code>).</li><li>Monitorar a saída estrutural em modo final local antes que a nuvem processe a página.</li></ul>',13)])])}const h=a(t,[["render",s]]);export{m as __pageData,h as default};
